// One-time shard rebuild script
import { readFileSync, writeFileSync, mkdirSync, readdirSync, unlinkSync } from 'fs';
import { join } from 'path';

const MEMORY_DIR = 'G:\\AI\\AIMemory';
const USER_ID = '509424983';
const shardDir = join(MEMORY_DIR, 'facts_Topic', USER_ID);

// Read topics.json (strip comments)
const topicsRaw = readFileSync(join(MEMORY_DIR, 'topics.json'), 'utf8');
const topicsClean = topicsRaw.replace(/^\s*\/\/.*/gm, '');
const topics = JSON.parse(topicsClean);

// Read master facts
const masterPath = join(MEMORY_DIR, `facts-${USER_ID}.md`);
const lines = readFileSync(masterPath, 'utf8').split(/\r?\n/).filter(l => l.startsWith('- [f_'));

console.log(`Master facts: ${lines.length}`);
console.log(`Topics: ${topics.length}`);

// Classify each fact
const shards = new Map();
for (const topic of topics) shards.set(topic.topic, []);
shards.set('misc', []);

for (const line of lines) {
  const lower = line.toLowerCase();
  let matched = false;
  for (const { topic, keywords } of topics) {
    for (const kw of keywords) {
      if (lower.includes(kw)) {
        shards.get(topic).push(line);
        matched = true;
        break;
      }
    }
    if (matched) break;
  }
  if (!matched) shards.get('misc').push(line);
}

// Clear old shards
mkdirSync(shardDir, { recursive: true });
for (const f of readdirSync(shardDir)) {
  if (f.endsWith('.md')) unlinkSync(join(shardDir, f));
}

// Write new shards
let total = 0;
for (const [topic, facts] of shards) {
  if (facts.length === 0) continue;
  writeFileSync(join(shardDir, `${topic}.md`), facts.join('\n') + '\n', 'utf8');
  console.log(`  ${topic}: ${facts.length}`);
  total += facts.length;
}
console.log(`Total classified: ${total}`);

